import { useNavigate, useLocation } from 'react-router-dom'
import { useCart } from '../contexts/CartContext'
import { formatPrice } from '../utils/helper'
import { BackIcon, TrashIcon, MinusIcon, PlusIcon } from '../components/Icons'

function QuantityControl({ quantity, onIncrement, onDecrement }) {
  return (
    <div className="flex items-center gap-2">
      <button
        onClick={onDecrement}
        className="h-6 w-6 grid place-items-center rounded border border-[#e4e4e7] bg-white text-[#1f2937] transition hover:bg-[#f3f4f6]"
      >
        -
      </button>
      <span className="text-[14px] font-medium">{quantity}</span>
      <button
        onClick={onIncrement}
        className="h-6 w-6 grid place-items-center rounded border border-[#e4e4e7] bg-white text-[#1f2937] transition hover:bg-[#f3f4f6]"
      >
        +
      </button>
    </div>
  )
}

function CartPage() {
  const navigate = useNavigate()
  const location = useLocation()
  const { 
    cartItems, 
    toggleSelected, 
    increment, 
    decrement, 
    remove,
    subtotal,
    totalSelectedQuantity,
    updateQuantity
   } = useCart()

  // 安全提取数据

  return (
    <>
        <div className="absolute inset-x-0 top-[44px] z-20 bg-white min-h-[44px]">
          <div className="mx-auto w-full max-w-[360px] px-5">
            <header className="flex min-h-[40px] items-center justify-between gap-2">
              <div className="flex min-w-0 items-center gap-3">
                <button
                  onClick={() => {
                    if (location.state?.from) {
                      navigate(-1)
                      return
                    }

                    navigate('/home')
                  }}
                  className="shrink-0 text-[#1C1B1B] transition hover:scale-110"
                  aria-label="Back"
                >
                  <BackIcon />
                </button>
                <h1 className="font-['Plus_Jakarta_Sans','Rubik',sans-serif] text-[25px] font-bold leading-[1.2] text-black">
                  My Cart
                </h1>
              </div>
            </header>
          </div>
        </div>

        <div className="hide-scrollbar absolute inset-x-0 bottom-[98px] top-[88px] overflow-y-auto pb-6">
            <div className="mx-auto w-full max-w-[360px] px-5 pt-4">

              {cartItems.length === 0 && (
                // 严厉纠正：空状态不需要白色卡片！必须占据全部高度并完美居中！
                <div className="mx-auto flex min-h-full w-full max-w-[360px] flex-col items-center justify-center px-5 pb-20 pt-10">
                  
                  <h2 className="mb-2 max-w-[280px] text-center text-[22px] font-bold leading-[1.3] text-[#1C1B1B]">
                    Your Cart Is Empty Now
                  </h2>
                  
                  <p className="mb-4 text-center text-[15px] font-medium text-[#6b7280]">
                    Browse and add some items!
                  </p>
  
                  {/* 严厉提醒：去把设计图里的那个购物车图片切出来放进 public 文件夹，然后把路径填在这里！ */}
                  <div className="mb-8 mr-5 h-[120px] w-[120px]">
                    <svg width="200" height="120" viewBox="0 0 260 160" fill="none" xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink">
                    <path d="M0 27C0 12.0883 12.0883 0 27 0H153C167.912 0 180 12.0883 180 27V133C180 147.912 167.912 160 153 160H27C12.0883 160 0 147.912 0 133V27Z" fill="url(#pattern0_5052_10572)"/>
                    <defs>
                    <pattern id="pattern0_5052_10572" patternContentUnits="objectBoundingBox" width="1" height="1">
                    <use xlinkHref="#image0_5052_10572" transform="matrix(0.002 0 0 0.00208276 -0.00125303 0.0736541)"/>
                    </pattern>
                    <image id="image0_5052_10572" width="500" height="500" preserveAspectRatio="none" xlinkHref="data:image/png;base64,"/>
                    </defs>
                    </svg>
                  </div>
  
                  <button
                    // 必须配置路由跳转：用户没有订单，当然要引导他们去主页或者商品列表页买东西！
                    onClick={() => navigate('/')} 
                    className="w-[200px] rounded-[14px] bg-[#1C1B1B] py-3.5 text-[16px] font-bold text-white shadow-lg transition-all hover:bg-black active:scale-95"
                  >
                    Order Now
                  </button>
  
                </div>
              )}  
                {cartItems.map((item) => (
                <div
                    key={item.id}
                    onClick={() => {navigate(`/product/${item.id}`)}}
                    // 外部容器：使用 flex items-stretch 确保左右两列等高
                    className="mb-4 flex w-full cursor-pointer items-stretch justify-between rounded-xl bg-white p-3 shadow-sm transition-all hover:shadow-md active:scale-[0.98]"
                >
                    {/* === 左侧：商品图片 === */}
                    <div className="mr-3 flex-shrink-0">
                    <img
                        src={item.image}
                        alt={item.name}
                        className="h-[100px] w-[70px] object-contain"
                    />
                    </div>

                    {/* === 中间：文字信息 + 数量控制 === */}
                    <div className="flex flex-1 flex-col justify-between py-1">
                      <div>
                          <p className="mb-1 text-[16px] font-medium leading-tight text-[#1C1B1B]">
                          {item.name}
                          </p>
                          <div className="flex flex-col">
                          <p className="text-[16px] font-bold text-[#1C1B1B]">
                              {formatPrice(item.price)}
                          </p>
                          {item.oldPrice ? (
                              <p className="text-[13px] text-[#EE4D4D] line-through">
                              {formatPrice(item.oldPrice)}
                              </p>
                          ) : null}
                          </div>
                      </div>
                    
                      {/* <div
                      className="mt-2"
                      onClick={(e) => e.stopPropagation()}
                      >
                          <QuantityControl
                          quantity={item.quantity}
                          onIncrement={() => increment(item.id)}
                          onDecrement={() => decrement(item.id)}
                          />
                      </div> */}
                      <div className="mt-2 w-fit">
                        <h3 className="mb-1 text-[15px] font-bold text-[#1C1B1B]">Quantity</h3>
                        <div
                          onClick={(e) => e.stopPropagation()} 
                          className="flex h-[42px] w-fit items-center justify-between rounded-xl border border-[#e4e4e7] px-2"
                        >
                          <button 
                            onClick={() => decrement(item.id)}
                            disabled={item.quantity <= 1}
                            className="p-1.5 text-[#1C1B1B] transition hover:opacity-70 active:scale-90"
                          >
                            <MinusIcon active={item.quantity > 1} />
                          </button>
                          
                          {/* 严厉纠正：这里必须是 input！ */}
                          <input
                            name="quantityForm"
                            type="number"
                            inputMode="numeric"
                            pattern="[0-9]*"
                            // 保证用户删空时输入框是空的，而不是显示难看的 0
                            value={item.quantity === '' ? '' : item.quantity} 
                            onChange={(e) => {
                              // 1. 拦截输入时的冒泡
                              e.stopPropagation();
                              
                              // 2. 拿到用户输入的值
                              const val = e.target.value;
                              
                              // 3. 允许用户把输入框删空（临时状态，为了方便重新输入数字）
                              if (val === '') {
                                updateQuantity(item.id, ''); 
                                return;
                              }
                              
                              // 4. 解析为整数并更新
                              const num = parseInt(val, 10);
                              if (!isNaN(num)) {
                                updateQuantity(item.id, num);
                              }
                            }}
                            onBlur={(e) => {
                              // 失去焦点时的终极防御：如果用户留空了，或者输入了 0，强制变回 1！
                              if (item.quantity === '' || item.quantity < 1) {
                                updateQuantity(item.id, 1);
                              }
                            }}
                            // Tailwind 隐藏原生箭头魔法：
                            // appearance-none 隐藏默认样式
                            // [&::-webkit-inner-spin-button]:appearance-none 隐藏 Chrome/Safari 的上下小箭头
                            // [&::-webkit-outer-spin-button]:appearance-none
                            // -moz-appearance: textfield 隐藏 Firefox 的箭头
                            className="w-10 appearance-none bg-transparent text-center text-[15px] font-semibold text-[#1C1B1B] outline-none [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none"
                          />

                          <button 
                            onClick={() => increment(item.id)}
                            disabled={item.quantity >= 99}
                            className="p-1.5 text-[#1C1B1B] transition hover:opacity-70 active:scale-90"
                          >
                            <PlusIcon active={item.quantity < 99} />
                          </button>
                        </div>
                      </div>
                    </div>

                    {/* === 右侧：复选框 (顶) + 垃圾桶 (底) === */}
                    <div className="ml-2 flex flex-col items-end justify-between py-1">
                    
                    {/* 使用 Tailwind 'peer' 技巧制作的自定义 Checkbox */}
                    {/* 右侧：复选框容器 */}
                    <label 
                    onClick={(e) => e.stopPropagation()}
                    className="relative flex cursor-pointer items-center justify-center">
                        {/* 1. 隐藏的原生 input */}
                        <input
                            type="checkbox"
                            checked={item.selected}
                            onChange={() => toggleSelected(item.id)}
                            className="peer sr-only" 
                        />

                        {/* 2. 占位容器 */}
                        {/* 我们给容器一个固定的宽高，默认只显示边框 */}
                        {/* <div className="flex h-6 w-6 items-center justify-center rounded-md border-2 border-[#e4e4e7] bg-transparent transition-all peer-checked:border-transparent"> */}
                        <div className="absolute inset-0 transition-opacity peer-checked:opacity-100 rounded-md border-2 border-[#e4e4e7] flex items-center justify-center">
                            
                            
                        
                        </div>
                         {/* 3. 你的自定义 SVG */}
                            {/* 默认 opacity-0 (隐藏)，当 peer-checked 时 opacity-100 (显示) */}
                            <div className="opacity-0 transition-opacity peer-checked:opacity-100">
                            <svg width="24" height="24" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path 
                                d="M14.19 0H5.81C2.17 0 0 2.17 0 5.81V14.18C0 17.83 2.17 20 5.81 20H14.18C17.82 20 19.99 17.83 19.99 14.19V5.81C20 2.17 17.83 0 14.19 0ZM14.78 7.7L9.11 13.37C8.97 13.51 8.78 13.59 8.58 13.59C8.38 13.59 8.19 13.51 8.05 13.37L5.22 10.54C4.93 10.25 4.93 9.77 5.22 9.48C5.51 9.19 5.99 9.19 6.28 9.48L8.58 11.78L13.72 6.64C14.01 6.35 14.49 6.35 14.78 6.64C15.07 6.93 15.07 7.4 14.78 7.7Z" 
                                fill="#38d4a4" // 统一颜色
                                />
                            </svg>
                        </div>

                    </label>

                    {/* 垃圾桶按钮 */}
                    <button
                        onClick={(e) => {
                          e.stopPropagation();
                          remove(item.id)}
                        }
                        className="text-[#ef4444] transition hover:scale-110 mb-1"
                    >
                        <TrashIcon />
                    </button>
                    </div>

                </div>
                ))}
            </div>
            </div>

        <div className="absolute bottom-0 left-0 z-20 w-full border-t border-[#e4e4e7] bg-[#f8fafc] pb-2 pt-3">
          <div className="mx-auto w-full max-w-[360px] px-5">
            <div className="mb-3 flex items-center justify-center gap-4">
              <span className="text-[16px] font-medium text-[#1f2937]">Subtotal</span>
              {/* 总价会自动根据打勾状态更新 */}
              <span className="text-[18px] font-bold text-[#42c236]">
                {formatPrice(subtotal)}
              </span>
            </div>
            
            {/* 按钮状态：如果没选商品，按钮应该变灰且不可点击 */}
            <button 
              disabled={totalSelectedQuantity === 0}
              onClick={() => {
                navigate('/payment', { state: { from: location.pathname }});
              }}
              className={`mb-2 w-full rounded-xl py-3 text-[15px] font-semibold text-white transition 
                ${totalSelectedQuantity === 0 
                  ? 'bg-gray-300 cursor-not-allowed' // 未选中任何商品时的灰色状态
                  : 'bg-[#111827] hover:bg-[#1f2937] shadow-lg hover:-translate-y-0.5' // 有选中商品时的黑色状态
                }`}
            >
              Payment ({totalSelectedQuantity})
            </button>
          </div>
        </div>
      </>
  )
}

export default CartPage
